import React, { useState } from "react";
import "./IndividualAnalysis.css";

function IndividualAnalysis({ 
  customerData = {}, 
  onInputChange, 
  onReset,
  loading, 
  results,
  setLoading,
  setResults
}) {
  const [activeTab, setActiveTab] = useState("core");

  const API_BASE_URL = "http://localhost:5000";

  const handleAnalyze = async () => {
    setLoading(true);
    
    try {
      console.log("Sending customer data:", customerData);

      const response = await fetch(`${API_BASE_URL}/api/predict`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(customerData),
      });

      const responseData = await response.json();
      console.log("API response:", responseData);

      if (!response.ok) {
        throw new Error(responseData.error || "Server error");
      }

      // 🔥 FIX: Backend does NOT send success=true, so don't check it
      if (responseData.probability !== undefined) {
        setResults(responseData);
      } else {
        alert("Prediction failed: Invalid response format");
      }

    } catch (error) {
      console.error("API Error:", error);
      alert(
        "Prediction failed!\n\n" +
        (error.message || "Unknown error")
      );
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    const { name, value, type } = e.target;
    const processedValue = type === "number" ? parseFloat(value) || 0 : value;
    onInputChange({ ...customerData, [name]: processedValue });
  };

  const handleNumberChange = (name, value) => {
    onInputChange({
      ...customerData,
      [name]: value === "" ? "" : parseFloat(value),
    });
  };

  const handleRangeChange = (name, value) => {
    onInputChange({ ...customerData, [name]: parseFloat(value) });
  };

  const toggleComplaint = () => {
    onInputChange({
      ...customerData,
      Complain: customerData.Complain === 1 ? 0 : 1,
    });
  };

  const renderField = (label, name, type = "number", options = null, step = 1, helpText = "") => {
    if (name === "SatisfactionScore") {
      return (
        <div className="field-container">
          <div className="field-header">
            <label className="field-label">{label}</label>
            {helpText && <span className="field-help" title={helpText}>ℹ️</span>}
          </div>

          <div className="range-slider-container">
            <input
              type="range"
              min="1"
              max="5"
              step="1"
              name={name}
              value={customerData[name] || 1}
              onChange={(e) => handleRangeChange(name, e.target.value)}
              className="range-slider"
            />

            <div className="range-labels">
              {[1, 2, 3, 4, 5].map((n) => (
                <span key={n} className="range-label">{n}</span>
              ))}
            </div>

            <div className="range-value-display">
              <span className="range-current-value">{customerData[name] || 1}</span>
              <span className="range-max-value">/5</span>
            </div>
          </div>
        </div>
      );
    }

    if (name === "Complain") {
      return (
        <div className="field-container">
          <div className="field-header">
            <label className="field-label">{label}</label>
          </div>

          <div className="toggle-button-container">
            <button
              type="button"
              className={`simple-toggle-btn ${customerData.Complain === 1 ? "active" : ""}`}
              onClick={toggleComplaint}
            >
              <span className="toggle-track">
                <span className="toggle-thumb"></span>
              </span>
              <span className="toggle-label">
                {customerData.Complain === 1 ? "Complaint Filed" : "No Complaint"}
              </span>
            </button>
          </div>
        </div>
      );
    }

    return (
      <div className="field-container">
        <div className="field-header">
          <label className="field-label">{label}</label>
          {helpText && <span className="field-help" title={helpText}>ℹ️</span>}
        </div>

        {options ? (
          <select
            name={name}
            value={customerData[name] || ""}
            onChange={handleChange}
            className="form-select"
          >
            <option value="">Select an option</option>
            {options.map((opt, i) => (
              <option key={i} value={opt}>
                {opt}
              </option>
            ))}
          </select>
        ) : (
          <input
            type="number"
            name={name}
            value={customerData[name] ?? ""}
            onChange={(e) => handleNumberChange(name, e.target.value)}
            step={step}
            min="0"
            className="form-input number-input-simple"
          />
        )}
      </div>
    );
  };

  const renderChurnRateCard = () => {
    if (!results) return null;

    const probability = results.probability || 0;
    const prediction = results.prediction || 0;

    const riskLevel =
      probability > 0.7 ? "high" : probability > 0.4 ? "medium" : "low";

    const riskColors = {
      high: "#ef4444",
      medium: "#f59e0b",
      low: "#10b981",
    };

    const riskLabels = {
      high: "HIGH RISK",
      medium: "MEDIUM RISK",
      low: "LOW RISK",
    };

    return (
      <div className="churn-rate-card">
        <h3>🎯 Churn Risk Analysis</h3>

        <div className="probability-display">
          <div className="probability-circle">
            <div
              className="circle-background"
              style={{
                background: `conic-gradient(${riskColors[riskLevel]} ${
                  probability * 100
                }%, #eee 0)`,
              }}
            ></div>
            <span className="probability-value">{(probability * 100).toFixed(1)}%</span>
          </div>

          <div className="probability-info">
            <div className={`risk-badge ${riskLevel}`}>
              {riskLabels[riskLevel]}
            </div>
            <p>{prediction ? "Likely to Churn" : "Likely to Stay"}</p>
          </div>
        </div>

        {/* Business impact */}
        {results.business_impact && (
          <div className="business-impact">
            <h4>Business Impact</h4>
            <p>Estimated CLV: ₹{results.business_impact.estimated_clv}</p>
            <p>Potential Loss: ₹{results.business_impact.potential_revenue_loss}</p>
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="individual-analysis">
      <div className="content-tabs">
        <button
          className={`tab-btn ${activeTab === "core" ? "active" : ""}`}
          onClick={() => setActiveTab("core")}
        >
          Core Metrics
        </button>

        <button
          className={`tab-btn ${activeTab === "logistics" ? "active" : ""}`}
          onClick={() => setActiveTab("logistics")}
        >
          Service & Logistics
        </button>

        <button
          className={`tab-btn ${activeTab === "demographics" ? "active" : ""}`}
          onClick={() => setActiveTab("demographics")}
        >
          Demographics
        </button>
      </div>

      <div className="content-panel">
        <div className="panel-header">
          <h2>Enter customer details to predict churn probability</h2>
        </div>

        {/* quick stats */}
        <div className="quick-stats">
          <div className="stat-card">
            <span className="stat-value">{customerData.Tenure}</span>
            <span className="stat-label">Months Tenure</span>
          </div>

          <div className="stat-card">
            <span className="stat-value">{customerData.OrderCount}</span>
            <span className="stat-label">Total Orders</span>
          </div>

          <div className="stat-card">
            <span className="stat-value">{customerData.SatisfactionScore}/5</span>
            <span className="stat-label">Satisfaction</span>
          </div>
        </div>

        {/* tab content */}
        <div className="tab-content-area">
          {activeTab === "core" && (
            <div className="fields-grid">
              {renderField("Tenure Duration", "Tenure")}
              {renderField("Total Order Count", "OrderCount")}
              {renderField("Cashback Amount (₹)", "CashbackAmount")}
              {renderField("Order Value Hike (%)", "OrderAmountHikeFromlastYear")}
              {renderField("Coupons Used", "CouponUsed")}
              {renderField("Devices Registered", "NumberOfDeviceRegistered")}
              {renderField("Satisfaction Score", "SatisfactionScore")}
            </div>
          )}

          {activeTab === "logistics" && (
            <div className="fields-grid">
              {renderField("Complaint Filed", "Complain")}
              {renderField("Days Since Last Order", "DaySinceLastOrder")}
              {renderField("Hours on App", "HourSpendOnApp")}
              {renderField("Warehouse Distance (km)", "WarehouseToHome")}
              {renderField("Delivery Addresses", "NumberOfAddress")}
              {renderField("Preferred Login Device", "PreferredLoginDevice", "select", [
                "Mobile Phone", "Computer", "Phone", "Tablet",
              ])}
              {renderField("Favorite Category", "PreferedOrderCat", "select", [
                "Laptop & Accessory",
                "Mobile & Accessory",
                "Grocery",
                "Fashion",
                "Electronics",
                "Beauty",
                "Books",
              ])}
            </div>
          )}

          {activeTab === "demographics" && (
            <div className="fields-grid">
              {renderField("Gender", "Gender", "select", ["Male", "Female", "Other"])}
              {renderField("Marital Status", "MaritalStatus", "select", [
                "Married",
                "Single",
                "Divorced",
                "Widowed",
              ])}
              {renderField("Payment Mode", "PreferredPaymentMode", "select", [
                "Credit Card",
                "Debit Card",
                "UPI",
                "Net Banking",
                "Cash on Delivery",
                "E-Wallet",
              ])}
              {renderField("City Tier", "CityTier", "select", [1, 2, 3])}
            </div>
          )}
        </div>

        {/* buttons */}
        <div className="action-buttons">
          <button className="btn secondary" onClick={onReset} disabled={loading}>
            Reset Form
          </button>

          <button className="btn primary" onClick={handleAnalyze} disabled={loading}>
            {loading ? "Analyzing..." : "Run Analysis"}
          </button>
        </div>

        {renderChurnRateCard()}
      </div>
    </div>
  );
}

export default IndividualAnalysis;
